    @Override
    public RekenContext berekenLoon(
            Admin admin, int persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, RekenMotorStrategy strategy,
            Rekenmodus rekenModus, String actor, CoreHrConfiguratie coreHrConfiguratie) throws Exception {
        return berekenLoon(admin, persoonId, opdrachtNrs, rekenTijd, strategy, rekenModus, actor, new RekenContext(), coreHrConfiguratie);
    }

    @Override
    public RekenContext berekenLoon(
            Admin admin, int persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, RekenMotorStrategy strategy,
            Rekenmodus rekenModus, String actor, RekenContext actionParams, CoreHrConfiguratie coreHrConfiguratie) throws Exception {
        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.berekenLoon");

        RekenChainFactory factory = strategy.getRekenChainFactory();
        ResultaatHandler handler = strategy.getResultaatHandler();
        RegulManagerFactory regulManagerFactory = strategy.getRegulManagerFactory();
        PreBerekeningInterpreter interpreter = strategy.getPreBerekeningInterpreter();
        TimeTools timeTools = new TimeTools(admin, constantService);

        TimeTools.checkRekenTijd(rekenTijd);

        if (rekenTijd.beslagDatum.isBefore(rekenTijd.beginDatum)) {
            rekenTijd =
                    new RekenTijd(rekenTijd.rekenPeriode, rekenTijd.rekenDatum, rekenTijd.boekDatum, rekenTijd.beginDatum, rekenTijd.rekenTijdstip,
                            rekenTijd.isAchterstal, rekenTijd.isApo);
        }

        boolean isApo = isApo(admin, rekenTijd);
        rekenTijd = RekenTijd.setIsApo(rekenTijd, isApo);

        Integer fiscaalJaar = timeTools.bepaalFiscaalJaar(rekenTijd);
        RegulManager regulManager = regulManagerFactory.getRegulManager();
        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        RekenFeedback feedback = new RekenFeedback();

        List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties = coreHrConfiguratie.getRkmCoreHrConfiguraties();
        List<PlanningsurenCoreHrConfiguratie> planningsurenConfiguraties = coreHrConfiguratie.getPlanningsurenCoreHrConfiguraties();
        RkmCoreHrConfiguratieManager coreHrConfiguratieManager = new RkmCoreHrConfiguratieManagerImpl(rkmCoreHrConfiguraties, planningsurenConfiguraties);

        PersoonsDataManager dataManager =
                persoonsDataManagerFactory.create(admin, persoonId, opdrachtNrs, rekenTijd, fiscaalJaar, regulManager, rekenModus);
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        if (persoon.getPersoonsFiscaliteitSlices().isEmpty()) {
            regulManager.addRegul(rekenTijd.beginDatum, null, Regulkode.PRSFISKALITEIT_NIET_GEVONDEN);
        }
        OpslaanNulResultaten statusOpslaanNulResultaten = statusOpslaanNulResultaten(admin, rekenTijd);


        RekenContext mainContext = new RekenContext();
        mainContext.put(REKEN_FEEDBACK_KEY, feedback);
        mainContext.put(REKENTIJD_KEY, rekenTijd);
        mainContext.put(FISCAAL_JAAR_KEY, fiscaalJaar);
        mainContext.put(REGUL_MANAGER_KEY, regulManager);
        mainContext.put(LOONCODE_MANAGER_KEY, loonCodeManager);
        mainContext.put(REKEN_CHAIN_FACTORY_KEY, factory);
        mainContext.put(PERSOONSDATA_MANAGER_KEY, dataManager);
        mainContext.put(PERSOON_KEY, persoon);
        mainContext.put(REKENMODUS_KEY, rekenModus);
        mainContext.put(ACTOR_KEY, actor);
        mainContext.put(OPSLAAN_NULRESULTATEN_KEY, statusOpslaanNulResultaten);
        mainContext.put(RKM_COREHR_CONFIG_MANAGER, coreHrConfiguratieManager);
        resultaatHandlerService.cleanResultaten(admin, handler, mainContext);

        log.trace("berekenLoon({}, {}-{}, {})", admin.getAdminDir(), persoonId, opdrachtNrs, rekenTijd);

        boolean isTeNegeren = handler.isTeNegeren(admin, rekenTijd.beginDatum, persoon);
        if (isTeNegeren) {
            log.info("persoonid:{} zit in wachtagenda. Berekening overslaan.", persoonId);
            TussenkomstManager tussenkomstManager = new TussenkomstManagerImp();
            ControlesRekenResultaten controles = new ControlesRekenResultaten(null, tussenkomstManager);
            List<ControleAgenda> bestaandeControles =
                    controleAgendaService.findOpenControles(admin, rekenTijd.rekenPeriode, persoon.getId(), opdrachtNrs, RekenControleCode.WACHTAGENDA);
            List<ControleAgenda> controleAgenda = new ArrayList<>();
            Set<Integer> bestaandeControlesOpdrachtNrs =
                    bestaandeControles.stream().map(ControleAgenda::getOpdrachtNummer).collect(Collectors.toSet());
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                if (!bestaandeControlesOpdrachtNrs.contains(opdracht.getOpdrachtnr())) {
                    controleAgenda.add(
                            controles.maakControleAgenda(RekenControleCode.WACHTAGENDA, opdracht, rekenTijd.beginDatum, "Er is een wachtagenda", actor));
                }
            }
            Integer rekenBatchNr = handler.getRekenBatchNr();
            if (rekenBatchNr != null) {
                controleAgenda.forEach(x -> x.setRekenBatchNr(rekenBatchNr));
            }
            controleAgendaService.create(admin, controleAgenda);
            regulManager.addWaarschuwingen(controleAgenda);
            feedback.setAantalControleAgendas(controleAgenda.size());
            feedback.setHasWachtagenda(true);
            return mainContext;
        }

        bepaalPersoonsInhoudingen(dataManager, admin, mainContext, persoon, rekenTijd);
        RekenContext preBerekeningContext = interpreter.vormPreBerekeningContext(persoon, dataManager, rekenTijd, regulManager);
        mainContext.put(PRE_BEREKENING_CONTEXT_KEY, preBerekeningContext);

        RekenContext preBerekeningContextVorigFiscaalJaar = bepaalPreBerekeningContextVorigFiscaalJaar(mainContext, fiscaalJaar);
        mainContext.put(PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY, preBerekeningContextVorigFiscaalJaar);

        MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten = bepaalToegepasteTussenkomsten(persoon, dataManager, rekenTijd, fiscaalJaar, regulManager);

        TussenkomstManager tussenkomstManager =
                getTussenkomstManager(admin, persoon, rekenTijd.rekenPeriode, loonCodeManager, toegepasteTussenkomsten);
        mainContext.put(TUSSENKOMST_MANAGER_KEY, tussenkomstManager);

        RekenChainType type = bepaalRekenChainType(admin, rekenTijd, rekenModus);

        RkmTijdperk tijdperk = getRkmTijdperk(rekenTijd, dataManager);
        Chain rekenChain = factory.getRekenChain(type, tijdperk);

        boolean stopState = regulManager.hasReguls() && !regulManager.hasIgnore();
        if (!stopState) {
            try {
                preRekenRegulChecks(mainContext);
                rekenChain.execute(mainContext);
                resultaatHandlerService.verwerkResultaten(admin, handler, mainContext);
            } catch (RegulException regulException) {
                regulManager.handleRegulException(rekenTijd, persoon, regulException);
            } catch (EndingRegulException regulException) {
                log.trace("EndingRegulException", regulException);
            }
        }
        regulManager.handleReguls(rekenTijd, persoon);
        resultaatHandlerService.verwerkReguls(admin, handler, mainContext, stopState);
        TimeLogContext.getInstance().endTimeLogging();
        return mainContext;
    }

    /**
     * Heel uitzonderlijk is het nodig om via DMFAPPL te rekenen bij een ontslag op START DMFA.
     * Aangezien je dan met het kengetal van de vorige periode moet rekenenen en die niet meer beschikbaar is in DMFA
     */
    private RkmTijdperk getRkmTijdperk(RekenTijd rekenTijd, PersoonsDataManager dataManager) {
        boolean uitzonderlijkDmfappl = false;
        if (rekenTijd.beginDatum.equals(RszConstants.START_DMFA)) {
            Persoon persoonOpDatum = dataManager.getPersoonOpDatum(RszConstants.START_DMFA.dayOfMonth().withMaximumValue());
            for (Opdracht opdracht : persoonOpDatum.getOpdrachten()) {
                uitzonderlijkDmfappl = dataManager.isOpdrachtInOpzegOpEerstDagKwartaal(opdracht);
                if (!uitzonderlijkDmfappl) {
                    break;
                }
            }
        }
        if (uitzonderlijkDmfappl) {
            return RkmTijdperk.DMFAPPL;
        } else {
            return RkmTijdperk.getTijdperk(rekenTijd);
        }
    }

    private MoneyMap<OpperAkeRegimeBedragTypeKey> bepaalToegepasteTussenkomsten(
            Persoon persoon, PersoonsDataManager dataManager, RekenTijd rekenTijd, Integer fiscaalJaar,
            RegulManager regulManager) {
        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        Map<Integer, AardKodeExtensie> akeIdToAardKodeExtensieMap = new HashMap<>();
        Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten = new HashMoneyMap<>();
        List<RekenHoofd> bestaanden = dataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() != null) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    for (ToegepasteTussenkomst toegepast : lijn.getToegepasteTussenkomsten()) {
                        Opdracht opdracht = idToOpdracht.get(hoofd.getOpdracht().getId());
                        Opper opper = RekenTools.findOpper(opdracht, lijn.getEindDatum());
                        if (opper == null) {
                            opper = RekenTools.getOpperLaatsteGegevens(opdracht);
                        }

                        AardKodeExtensie looncode = akeIdToAardKodeExtensieMap.get(lijn.getAardKodeExtensie().getId());
                        if (looncode == null) {
                            looncode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());
                            akeIdToAardKodeExtensieMap.put(looncode.getId(), looncode);
                        }
                        if (!hoofd.getFiscaalJaar().equals(fiscaalJaar)) {
                            OpperAkeRegimeBedragTypeKey key =
                                    new OpperAkeRegimeBedragTypeKey(opper, looncode, lijn.getRegimeBv(), toegepast.getBedragType());
                            toegepasteTussenkomsten.addToMoney(key, toegepast.getBedrag());
                        }
                    }
                }
            }
        }
        return toegepasteTussenkomsten;
    }

    private void preRekenRegulChecks(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        Rekenmodus rekenModus = context.getUnchecked(REKENMODUS_KEY);
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        PersoonsDataManager dataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        if (rekenTijd.isApo && rekenModus == Rekenmodus.VOORSCHOT) {
            regulManager.doRegulException(null, Regulkode.VOORSCHOT_APO);
        } else if (rekenModus == Rekenmodus.VOORSCHOT) {
            List<RekenHoofd> bestaanden = dataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
            for (RekenHoofd hoofd : bestaanden) {
                if (hoofd.getRekenModus() != Rekenmodus.VOORSCHOT && hoofd.getRnummer() != null && hoofd.getRekenLijnen().stream()
                        .flatMap(x -> x.getRekenBedragen().stream()).anyMatch(x -> x.getBedrag().signum() != 0)) {
                    regulManager.doRegulException(hoofd.getOpdracht(), Regulkode.VOORSCHOT_NORMAAL_AANWEZIG);
                }
            }
        }
    }

    private RekenChainType bepaalRekenChainType(Admin admin, RekenTijd rekenTijd, Rekenmodus rekenModus) {
        boolean isAchterstal = isAchterstal(admin, rekenTijd);
        RekenChainType type;
        if (rekenModus == Rekenmodus.VOORSCHOT) {
            type = RekenChainType.VOORSCHOT;
        } else if (rekenTijd.isApo) {
            type = RekenChainType.APO;
        } else if (isAchterstal) {
            type = RekenChainType.ACHTERSTAL;
        } else {
            type = RekenChainType.NORMAAL;
        }
        return type;
    }

    private boolean isAchterstal(Admin admin, RekenTijd rekenTijd) {
        return rekenTijd.isApo || !rekenTijd.rekenDatum.isBefore(getDatumAfsluitenFiscaalJaar(admin, rekenTijd));
    }

    private boolean isApo(Admin admin, RekenTijd rekenTijd) {
        LocalDate datumAansluiting = constantService.getByCodeDatum(admin, Konstanten.KST_STARTDATUM_SWEEP, rekenTijd.beginDatum).getDatum();
        return datumAansluiting.compareTo(rekenTijd.beginDatum) > 0;
    }

    private LocalDate getDatumAfsluitenFiscaalJaar(Admin admin, RekenTijd rekenTijd) {
        Constant constante = constantService.getByCodeDatum(admin, Konstanten.KST_FISKAAL_JAAR, rekenTijd.beginDatum);
        return constante.getDatum();
    }

    private OpslaanNulResultaten statusOpslaanNulResultaten(Admin admin, RekenTijd rekenTijd) {
        Constant constante = constantService.getByCodeDatum(admin, Konstanten.KST_NULRESULTATEN_BEWAREN, rekenTijd.beginDatum);
        OpslaanNulResultaten status = OpslaanNulResultaten.getByCode(constante.getInteger());
        return status != null ? status : OpslaanNulResultaten.NIET_OPSLAAN;
    }

    private RekenContext bepaalPreBerekeningContextVorigFiscaalJaar(RekenContext mainContext, Integer huidigFiscaalJaar) {
        RekenContext preBerekeningContext = mainContext.getUnchecked(PRE_BEREKENING_CONTEXT_KEY);
        Integer preFiscaalJaar = preBerekeningContext.getInteger(FISCAAL_JAAR_KEY);
        while (preFiscaalJaar.compareTo(huidigFiscaalJaar) >= 0) {
            preBerekeningContext = preBerekeningContext.getUnchecked(PRE_BEREKENING_CONTEXT_KEY);
            preFiscaalJaar = preBerekeningContext.getInteger(FISCAAL_JAAR_KEY);
        }
        return preBerekeningContext;
    }

    //TODO lijkt gedeeltelijk thuis te horen in persoonsdatamanager
    public void bepaalPersoonsInhoudingen(PersoonsDataManager dataManager, Admin admin, RekenContext context, Persoon persoon, RekenTijd rekenTijd) {
        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.bepaalPersoonsInhoudingen");
        List<PersoonsInhouding> persoonsInhoudingen = dataManager.findPersoonsInhoudingenOpBeslagDatum(rekenTijd.beslagDatum);

        PersoonsInhouding onderhoudsgeld = null;
        PersoonsInhouding beslagOpLoon = null;
        for (PersoonsInhouding persoonInhouding : persoonsInhoudingen) {
            if (persoonInhouding.getCode() == BerekenBeslagOpLoon.ONDERHOUDSGELD_BLO_CODE) {
                if (onderhoudsgeld != null) {
                    //TODO throw regul
                }
                onderhoudsgeld = persoonInhouding;
            } else if (persoonInhouding.getCode() == BerekenBeslagOpLoon.BESLAG_OP_LOON_CODE) {
                if (beslagOpLoon != null) {
                    //TODO throw regul
                }
                beslagOpLoon = persoonInhouding;
            }
        }
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        Clustermapping clusterMapping = clusterMappingService.getByAdmin(admin);
        Cluster cluster = null;
        if (clusterMapping != null) {
            cluster = clusterService.getById(clusterMapping.getClusterId());
        }

        context.put(PERSOON_INHOUDING_ONDERHOUDSGELD, vormBeslagOpLoonInfo(cluster, admin, onderhoudsgeld, persoon, rekenTijd, loonCodeManager));
        context.put(PERSOON_INHOUDING_BESLAG_OP_LOON, vormBeslagOpLoonInfo(cluster, admin, beslagOpLoon, persoon, rekenTijd, loonCodeManager));

        if (beslagOpLoon != null || onderhoudsgeld != null) {
            TimeLogContext.getInstance().startTimeLogging("RekenMotorService.rekenResultatenService.findByOpdrachtenBeslagDatum");
            List<RekenHoofd> beslagMaandResultaten =
                    TemporalUtil.getActualFree(() -> rekenResultatenService.findByPersoonIdBeslagDatum(admin, persoon.getId(), rekenTijd.beslagDatum));
            TimeLogContext.getInstance().endTimeLogging();
            context.put(BESLAG_MAAND_RESULTATEN_KEY, beslagMaandResultaten);
            PersoonsFiscaliteit beslagPersoonsFiscaliteit = dataManager.getPersoonsFiscaliteitOpBeslagDatum(rekenTijd.beslagDatum);
            context.put(BESLAG_MAAND_PERSOONSFISCALITEIT_KEY, beslagPersoonsFiscaliteit);
        }
        TimeLogContext.getInstance().endTimeLogging();
    }

    private BeslagOpLoonInfo vormBeslagOpLoonInfo(
            Cluster cluster, Admin admin, PersoonsInhouding persoonsInhouding, Persoon persoon,
            RekenTijd rekenTijd, LoonCodeManager loonCodeManager) {
        BeslagOpLoonInfo beslagOpLoonInfo = null;
        if (persoonsInhouding != null) {
            AardKodeExtensie loonCode = loonCodeManager
                    .getByTake(persoonsInhouding.getTijdperk(), persoonsInhouding.getAard(), persoonsInhouding.getCode(),
                            persoonsInhouding.getExtensie());
            beslagOpLoonInfo = new BeslagOpLoonInfo(persoonsInhouding, loonCode);
            if (cluster != null) {
                List<HrWageGarnishment> garnishes =
                        hrWageGarnishmentService.getByAdminPersoonAardKodeExtensie(cluster, admin, persoon, loonCode, rekenTijd.beslagDatum);
                if (!garnishes.isEmpty()) {
                    beslagOpLoonInfo.setExtraInfo(garnishes.get(0), garnishes.get(0).getAutomaticDeposit());
                } else {
                    beslagOpLoonInfo.setExtraInfo(null, false);
                }
            }
        }
        return beslagOpLoonInfo;
    }

    private TussenkomstManager getTussenkomstManager(
            Admin admin, Persoon persoon, LocalDateInterval rekenPeriode, LoonCodeManager loonCodeManager,
            MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten) {
        TussenkomstManager tussenkomstManager = new TussenkomstManagerImp();
        List<ManueleTussenkomst> tussenkomsten = manueleTussenkomstService.findByOpdrachtenPeriode(admin, persoon.getOpdrachten(), rekenPeriode);

        Map<Integer, Opdracht> idToOpdrachtMap = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
        for (ManueleTussenkomst tussenkomst : tussenkomsten) {
            Opdracht opdracht = idToOpdrachtMap.get(tussenkomst.getOpdracht().getId());
            LocalDate selectieDatum = tussenkomst.getDatum();
            if (selectieDatum.isAfter(opdracht.getEindDatum())) {
                selectieDatum = opdracht.getEindDatum();
            } else if (selectieDatum.isBefore(opdracht.getBeginDatum())) {
                selectieDatum = opdracht.getBeginDatum();
            }
            Opper opper = RekenTools.findOpper(opdracht, selectieDatum);
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getById(tussenkomst.getAardKodeExtensie().getId());
            tussenkomst.setAardKodeExtensie(aardKodeExtensie);
            tussenkomstManager.addTussenkomst(tussenkomst, opper);
        }

        List<SleutelTussenkomstHoofd> sleuteltussenkomsten =
                sleutelTussenkomstService.findByOpdrachtenPeriode(admin, persoon.getOpdrachten(), rekenPeriode);

        for (SleutelTussenkomstHoofd tussenkomst : sleuteltussenkomsten) {
            for (SleutelTussenkomstLijn tussenkomstLijn : tussenkomst.getLijnen()) {
                AardKodeExtensie aardKodeExtensie = loonCodeManager.getById(tussenkomstLijn.getAardKodeExtensie().getId());
                tussenkomstLijn.setAardKodeExtensie(aardKodeExtensie);
            }
            tussenkomstManager.addSleutelTussenkomst(tussenkomst);
        }
        tussenkomstManager.setToegepasteTussenkomsten(toegepasteTussenkomsten);
        return tussenkomstManager;
    }

